// src/components/Settings.js
import React, { useState } from 'react';
import './Settings.css';
import AddStudent from './AddStudent'; // Import AddStudent component

const AdminLogin = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [selectedOption, setSelectedOption] = useState(''); // To track the selected option

  const handleLogin = (e) => {
    e.preventDefault();
    if (username === ' ' && password === 'v') {  // Change credentials as needed
      setIsLoggedIn(true);
    } else {
      alert('Invalid credentials');
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUsername('');
    setPassword('');
    setSelectedOption(''); // Reset the selected option on logout
  };

  const handleOptionSelect = (option) => {
    setSelectedOption(option); // Set the selected option when clicked
  };

  return (
    <div className="admin-layout">
      {!isLoggedIn ? (
        <div className="admin-login-container">
          <h2>Admin Login</h2>
          <form onSubmit={handleLogin}>
            <div className="input-group">
              <label>Username:</label>
              <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} required />
            </div>
            <div className="input-group">
              <label>Password:</label>
              <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            <div className="button-container">
              <button type="submit">Login</button>
            </div>
          </form>
        </div>
      ) : (
        <div className="admin-panel-wrapper">
          {/* Admin Panel Options */}
          <div className="admin-panel">
            <h3>Admin Panel</h3>
            <p>Modify Admin Data and Password</p>
            <button className="settings-button" onClick={() => handleOptionSelect('adminUserModification')}>Go to Admin User Modification</button>
          </div>
          <div className="admin-panel">
            <h3>Student Timetable Panel</h3>
            <p>Modify Student Timetable and Allocated Rooms</p>
            <button className="settings-button" onClick={() => handleOptionSelect('addStudent')}>Go to Student Data</button>
          </div>

          {/* Conditional Rendering for Options */}
          {selectedOption === 'adminUserModification' && (
            <div className="admin-user-modification">
              <h3>Admin User Modification</h3>
              <p>Modify Admin Details Here</p>
              {/* Implement Admin User Modification functionality here */}
            </div>
          )}

          {selectedOption === 'addStudent' && (
            <div className="add-student-panel">
              <h3>Student Data</h3>
              <AddStudent /> {/* Render AddStudent Component */}
            </div>
          )}

          <button onClick={handleLogout} className="back-button">Back to Login</button>
        </div>
      )}
    </div>
  );
};

export default AdminLogin;
